from typing import List

class Solution:

def find(self, n: int, target: int, nums: List[int]) -> int:
	left, right = 0, n - 1
	while left <= right:
		mid = left + (right - left) // 2
		if nums[mid] == target:
			while mid > 0 and nums[mid - 1] == target:
				mid -= 1
			return mid
		elif nums[mid] < target:
			left = mid + 1
		else:
			# Continue searching in the left half
			right = mid - 1
		return -1
if __name__ == '__main__':
	arr = list(map(int, input().split()))
	target = int(input())
	print(Solution().find(len(arr), target, arr))

